phase1.code:
package main

import (
    "fmt"
    "strconv"
)

func main() {
    // ---- Empty interface (interface{}) ----
    // Can hold any type
    var anything interface{}

    // ---- Storing different types ----
    anything = 42
    fmt.Printf("int: %v, type: %T\n", anything, anything)

    anything = "Hello"
    fmt.Printf("string: %v, type: %T\n", anything, anything)

    anything = true
    fmt.Printf("bool: %v, type: %T\n", anything, anything)

    anything = []int{1, 2, 3}
    fmt.Printf("slice: %v, type: %T\n", anything, anything)

    // ---- Type assertion ----
    // Get the underlying value
    val, ok := anything.([]int)
    if ok {
        fmt.Println("It's a slice:", val)
    }

    // ---- Type switch ----
    // Check the type of the value
    printType(42)
    printType("Hello")
    printType(true)
    printType([]int{1, 2, 3})

    // ---- Empty interface as parameter ----
    // Can accept any type
    printValue(42)
    printValue("Hello")
    printValue(3.14)

    // ---- Map with empty interface ----
    data := map[string]interface{}{
        "name":   "Hero",
        "health": 100,
        "alive":  true,
        "items":  []string{"Sword", "Shield"},
    }

    fmt.Println("\nData:", data)

    // ---- Slice of empty interface ----
    mixed := []interface{}{42, "Hello", true, 3.14}
    for _, v := range mixed {
        fmt.Printf("%v (type: %T)\n", v, v)
    }
}

func printType(i interface{}) {
    switch v := i.(type) {
    case int:
        fmt.Printf("Integer: %d\n", v)
    case string:
        fmt.Printf("String: %s\n", v)
    case bool:
        fmt.Printf("Boolean: %t\n", v)
    case []int:
        fmt.Printf("Int slice: %v\n", v)
    default:
        fmt.Printf("Unknown type: %T\n", v)
    }
}

func printValue(v interface{}) {
    fmt.Printf("Value: %v\n", v)
}

phase2.brokenCode:
package main

import "fmt"

func main() {
    var i interface{} = 42
    // Type assertion without checking
    s := i.(string)  // Panic!
    fmt.Println(s)
}

phase2.explanation:
Type assertion without checking causes a panic if the type doesn't match.

**The fix:**
```go
s, ok := i.(string)
if ok {
    fmt.Println(s)
} else {
    fmt.Println("Not a string")
}
```

**Go-chan says:**
"Always use the `ok` pattern with type assertions."

phase3.solution:
package main

import "fmt"

func main() {
    values := []interface{}{42, "Hello", true, 3.14}

    for _, v := range values {
        switch val := v.(type) {
        case int:
            fmt.Printf("Integer: %d\n", val)
        case string:
            fmt.Printf("String: %s\n", val)
        case bool:
            fmt.Printf("Boolean: %t\n", val)
        case float64:
            fmt.Printf("Float: %f\n", val)
        default:
            fmt.Println("Unknown")
        }
    }
}
